import Foundation

public enum LogPurgeError: Error {
    case readFailed(path: String, underlying: any Error)
    case writeFailed(path: String, underlying: any Error)
}

public enum LogLevel: Int, Comparable, Sendable {
    case debug = 0, info, warning, error

    public static func < (lhs: LogLevel, rhs: LogLevel) -> Bool { lhs.rawValue < rhs.rawValue }

    var label: String {
        switch self {
        case .debug: "DEBUG"
        case .info: "INFO"
        case .warning: "WARN"
        case .error: "ERROR"
        }
    }

    public static func from(string: String) -> LogLevel {
        switch string.lowercased() {
        case "debug": .debug
        case "warning", "warn": .warning
        case "error": .error
        default: .info
        }
    }
}

public final class FileLogger: Sendable {
    public let filePath: String
    public let minLevel: LogLevel
    private let maxBytes: UInt64 = 5 * 1024 * 1024
    private let queue = DispatchQueue(label: "FileLogger.serialQueue")

    public init(filePath: String, minLevel: LogLevel = .info) {
        self.filePath = filePath
        self.minLevel = minLevel
        let dir = (filePath as NSString).deletingLastPathComponent
        do {
            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
        } catch {
            fputs("FileLogger: cannot create log directory \(dir): \(error)\n", stderr)
        }
    }

    public func log(_ level: LogLevel, _ message: String) {
        guard level >= minLevel else { return }
        append(level: level, message: message)
    }

    /// Blocks until all previously submitted log entries have been written to disk.
    /// Intended for tests that inspect log file contents after calling `log()`.
    func waitForPendingWrites() {
        queue.sync {}
    }

    // MARK: - Purge

    /// Removes log lines whose leading ISO 8601 timestamp is older than `cutoff`.
    /// Lines without a parseable timestamp (continuation / malformed) follow the
    /// fate of the preceding timestamped line.
    ///
    /// **Must not** be called from within `queue` — it dispatches synchronously
    /// to `queue` internally and would deadlock.
    public func purgeEntries(olderThan cutoff: Date) throws {
        var captured: (any Error)?
        queue.sync {
            do {
                try self.purgeFile(atPath: self.filePath, cutoff: cutoff)
                let backup = self.filePath + ".1"
                if FileManager.default.fileExists(atPath: backup) {
                    try self.purgeFile(atPath: backup, cutoff: cutoff)
                }
            } catch {
                captured = error
            }
        }
        if let captured { throw captured }
    }

    // MARK: - Private

    private func purgeFile(atPath path: String, cutoff: Date) throws {
        guard FileManager.default.fileExists(atPath: path) else { return }

        let original: String
        do {
            // WHY: reading into memory is acceptable — rotation caps files at 5 MB
            original = try String(contentsOfFile: path, encoding: .utf8)
        } catch {
            throw LogPurgeError.readFailed(path: path, underlying: error)
        }

        let formatter = ISO8601DateFormatter()
        let lines = original.split(separator: "\n", omittingEmptySubsequences: false)
        var kept: [Substring] = []
        var keepingContinuation = true

        for line in lines {
            if let date = parseLeadingTimestamp(from: line, formatter: formatter) {
                if date >= cutoff {
                    kept.append(line)
                    keepingContinuation = true
                } else {
                    keepingContinuation = false
                }
            } else {
                // Continuation / malformed line — follows fate of preceding timestamped line
                if keepingContinuation {
                    kept.append(line)
                }
            }
        }

        let result = kept.joined(separator: "\n")
        guard result != original else { return }

        do {
            let url = URL(fileURLWithPath: path)
            try result.data(using: .utf8)!.write(to: url, options: .atomic)
        } catch {
            throw LogPurgeError.writeFailed(path: path, underlying: error)
        }
    }

    private func parseLeadingTimestamp(from line: Substring, formatter: ISO8601DateFormatter) -> Date? {
        guard let open = line.firstIndex(of: "["),
              let close = line[line.index(after: open)...].firstIndex(of: "]") else {
            return nil
        }
        let stamp = String(line[line.index(after: open)..<close])
        return formatter.date(from: stamp)
    }

    private func append(level: LogLevel, message: String) {
        queue.async { [self] in
            // Per-call allocation — ISO8601DateFormatter is not thread-safe;
            // acceptable here because logging is a cold path
            let timestamp = ISO8601DateFormatter().string(from: Date())
            let entry = "[\(timestamp)] [\(level.label)] \(message)\n"
            guard let data = entry.data(using: .utf8) else { return }
            if !FileManager.default.fileExists(atPath: self.filePath) {
                FileManager.default.createFile(atPath: self.filePath, contents: nil)
            }

            self.rotateIfNeeded()

            guard let handle = FileHandle(forWritingAtPath: self.filePath) else { return }
            defer { handle.closeFile() }
            handle.seekToEndOfFile()
            handle.write(data)
        }
    }

    private func rotateIfNeeded() {
        guard let attrs = try? FileManager.default.attributesOfItem(atPath: filePath),
              let size = attrs[.size] as? UInt64,
              size > maxBytes else { return }
        let backup = filePath + ".1"
        try? FileManager.default.removeItem(atPath: backup)
        do {
            try FileManager.default.moveItem(atPath: filePath, toPath: backup)
        } catch {
            fputs("FileLogger: rotation failed for \(filePath): \(error)\n", stderr)
        }
        FileManager.default.createFile(atPath: filePath, contents: nil)
    }
}

// MARK: - Shared loggers

public enum Loggers {
    private static let cacheDir: String = {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        return "\(home)/.cache/ai-usages-tracker"
    }()

    private static let level: LogLevel = {
        LogLevel.from(string: ProcessInfo.processInfo.environment["AI_TRACKER_LOG_LEVEL"] ?? "info")
    }()

    public static let app = FileLogger(filePath: "\(cacheDir)/app.log", minLevel: level)
    public static let claude = FileLogger(filePath: "\(cacheDir)/claude-usages-connector.log", minLevel: level)

    public static let managed: [FileLogger] = [app, claude]
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

// Guarded by NSLock — all access goes through lock/unlock // justification: test-only counter
private final class AtomicCounter: @unchecked Sendable {
    private let lock = NSLock()
    private var _value = 0

    var value: Int {
        lock.lock()
        defer { lock.unlock() }
        return _value
    }

    func increment() {
        lock.lock()
        _value += 1
        lock.unlock()
    }
}

@Suite("LogCleaner")
struct LogCleanerTests {
    private func makeTempLogger() -> FileLogger {
        let path = NSTemporaryDirectory() + "ai-tracker-log-\(UUID().uuidString)/test.log"
        return FileLogger(filePath: path, minLevel: .debug)
    }

    private func writeLines(_ lines: String, to logger: FileLogger) throws {
        try lines.data(using: .utf8)!.write(to: URL(fileURLWithPath: logger.filePath), options: .atomic)
    }

    @Test("cleanOnce purges old lines from all managed loggers")
    func cleanOncePurgesAll() async throws {
        let logger1 = makeTempLogger()
        let logger2 = makeTempLogger()
        let fmt = ISO8601DateFormatter()
        let fixedNow = Date()
        let eightDaysAgo = fixedNow.addingTimeInterval(-8 * 24 * 60 * 60)
        let sixDaysAgo = fixedNow.addingTimeInterval(-6 * 24 * 60 * 60)

        let old = fmt.string(from: eightDaysAgo)
        let recent = fmt.string(from: sixDaysAgo)

        try writeLines("[\(old)] [INFO] old\n[\(recent)] [INFO] recent\n", to: logger1)
        try writeLines("[\(old)] [INFO] old\n", to: logger2)

        let cleaner = LogCleaner(
            loggers: [logger1, logger2],
            now: { fixedNow },
            logger: logger1
        )
        await cleaner.cleanOnce()

        let content1 = try String(contentsOfFile: logger1.filePath, encoding: .utf8)
        #expect(content1 == "[\(recent)] [INFO] recent\n")

        let content2 = try String(contentsOfFile: logger2.filePath, encoding: .utf8)
        #expect(content2 == "")
    }

    @Test("start is idempotent — second call does not spawn a second task")
    func startIdempotent() async throws {
        let logger = makeTempLogger()
        let counter = AtomicCounter()

        let cleaner = LogCleaner(
            loggers: [logger],
            tickInterval: .milliseconds(10),
            now: { Date() },
            sleep: { duration in
                counter.increment()
                try await Task.sleep(for: duration)
            },
            logger: logger
        )

        await cleaner.start()
        await cleaner.start() // second call — should be no-op

        try await Task.sleep(for: .milliseconds(100))

        let count = counter.value
        // If two tasks were spawned, count would roughly double.
        #expect(count < 20, "Too many sleep calls (\(count)), likely two tasks running")

        await cleaner.stop()
    }

    @Test("stop cancels the task and start can resume")
    func stopThenRestart() async throws {
        let logger = makeTempLogger()
        let counter = AtomicCounter()

        let cleaner = LogCleaner(
            loggers: [logger],
            tickInterval: .milliseconds(10),
            now: { Date() },
            sleep: { duration in
                counter.increment()
                try await Task.sleep(for: duration)
            },
            logger: logger
        )

        await cleaner.start()
        try await Task.sleep(for: .milliseconds(50))
        await cleaner.stop()

        let countAfterStop = counter.value

        try await Task.sleep(for: .milliseconds(50))
        let countLater = counter.value
        #expect(countLater == countAfterStop, "Ticks continued after stop")

        // Restart should work
        await cleaner.start()
        try await Task.sleep(for: .milliseconds(50))
        await cleaner.stop()

        let countAfterRestart = counter.value
        #expect(countAfterRestart > countAfterStop, "No ticks after restart")
    }

    @Test("cleanOnce handles missing files without crash")
    func cleanOnceMissingFile() async {
        let logger = makeTempLogger()
        let cleaner = LogCleaner(
            loggers: [logger],
            now: { Date() },
            logger: logger
        )
        await cleaner.cleanOnce()
    }

    @Test("clock injection drives the cutoff correctly")
    func clockInjection() async throws {
        let logger = makeTempLogger()
        let fmt = ISO8601DateFormatter()
        let fixedNow = Date()
        let almostSevenDays = fixedNow.addingTimeInterval(-6 * 24 * 60 * 60 - 23 * 60 * 60)
        let justOverSevenDays = fixedNow.addingTimeInterval(-7 * 24 * 60 * 60 - 60 * 60)

        let kept = fmt.string(from: almostSevenDays)
        let dropped = fmt.string(from: justOverSevenDays)

        try writeLines("[\(dropped)] [INFO] dropped\n[\(kept)] [INFO] kept\n", to: logger)

        let cleaner = LogCleaner(
            loggers: [logger],
            now: { fixedNow },
            logger: logger
        )
        await cleaner.cleanOnce()

        let content = try String(contentsOfFile: logger.filePath, encoding: .utf8)
        #expect(content == "[\(kept)] [INFO] kept\n")
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

@Suite("FileLogger")
struct FileLoggerTests {
    private func makeTempPath() -> String {
        NSTemporaryDirectory() + "ai-tracker-log-\(UUID().uuidString)/test.log"
    }

    @Test("creates directory and log file on first write")
    func createsFile() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .debug)
        logger.log(.info, "hello")
        logger.waitForPendingWrites()
        #expect(FileManager.default.fileExists(atPath: path))
    }

    @Test("respects minimum log level")
    func respectsMinLevel() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .warning)
        logger.log(.debug, "should not appear")
        logger.log(.info, "should not appear")
        logger.log(.warning, "should appear")
        logger.waitForPendingWrites()
        let content = try! String(contentsOfFile: path, encoding: .utf8)
        #expect(!content.contains("should not appear"))
        #expect(content.contains("should appear"))
    }

    @Test("log entry format contains timestamp and level")
    func logFormat() {
        let path = makeTempPath()
        let logger = FileLogger(filePath: path, minLevel: .debug)
        logger.log(.error, "test message")
        logger.waitForPendingWrites()
        let content = try! String(contentsOfFile: path, encoding: .utf8)
        #expect(content.contains("[ERROR]"))
        #expect(content.contains("test message"))
        #expect(content.contains("[20")) // ISO8601 year prefix
    }

    @Test("LogLevel.from parses strings correctly")
    func logLevelFromString() {
        #expect(LogLevel.from(string: "debug") == .debug)
        #expect(LogLevel.from(string: "DEBUG") == .debug)
        #expect(LogLevel.from(string: "warning") == .warning)
        #expect(LogLevel.from(string: "warn") == .warning)
        #expect(LogLevel.from(string: "error") == .error)
        #expect(LogLevel.from(string: "info") == .info)
        #expect(LogLevel.from(string: "garbage") == .info)
    }

    @Test("LogLevel comparison works")
    func logLevelComparison() {
